<div id="modal_detail_content" class="modal-dialog modal-lg" role="document" style="min-width: 80%;">    <div class="modal-content">        <div class="modal-header">            <button group="button" class="close" data-dismiss="modal" aria-label="Close">                <span aria-hidden="true">&times;</span></button>            <h4 class="modal-title" id="myModalLabel">                <span class="title in-title">                     {{!empty($title) ? $title : ''}}                </span>            </h4>        </div>        <form id="form-detail_content"              enctype="multipart/form-data"              action="admin/script/submit_content/{{$script->id ?? ''}}"              method="post" data-parsley-validate novalidate>            {{csrf_field()}}            <div class="modal-body">                <div class="row">                    <div class="col-md-12">                        <div class="panel-body">                            <div class="col-md-12">                                <div class="row">                                    <ul class="nav nav-tabs nav-justified row">                                        @foreach($language as $lang)                                            <li class="tab-btn {{$lang->is_default ? 'active' : ''}}">                                                <a href="#tab-info-{{$lang->code}}" data-toggle="tab" aria-expanded="false">                                                    <span class="visible-xs"><i class="fa fa-home"></i></span>                                                    <span class="hidden-xs">{{$lang->name}}</span>                                                </a>                                            </li>                                        @endforeach                                    </ul>                                </div>                                <div class="clearfix"></div>                                <div class="tab-content row m-t-20" style="padding-left:10px;padding-right:10px;">                                    @foreach($language as $lang)                                        <div id="tab-info-{{$lang->code}}" class="tab-pane fade {{$lang->is_default ? 'in active' : ''}}">                                            <div class="form-group">                                                <label for="content_{{$lang->code}}">{{lang('c_script_content')}} - {{$lang->name}}</label>                                                <textarea type="text" name="content[{{$lang->code}}]" class="form-control name">{{!empty($script->translations[$lang->code]['content']) ? $script->translations[$lang->code]['content'] : ''}}</textarea>                                            </div>                                        </div>                                    @endforeach                                </div>                            </div>                        </div>                    </div>                </div>                <div class="clearfix"></div>                <div class="modal-footer mtop10">                    <button type="button" class="btn btn-default" data-dismiss="modal">{{lang('dt_close')}}</button>                    <button type="submit" class="btn btn-info">{{lang('dt_save')}}</button>                </div>            </div>        </form>    </div><script>    $("#form-detail_content").validate({        rules: {},        messages: {},        submitHandler: function (form) {            var url = form.action;            var form = $(form),                formData = new FormData(),                formParams = form.serializeArray();            $.each(form.find('input[type="file"]'), function (i, tag) {                $.each($(tag)[0].files, function (i, file) {                    formData.append(tag.name, file);                });            });            $.each(formParams, function (i, val) {                formData.append(val.name, val.value);            });            $.ajax({                url: url,                type: 'POST',                dataType: 'JSON',                cache: false,                contentType: false,                processData: false,                data: formData,            }).done(function (response) {                if (response.result == true) {                    alert_float('success', response.message);                }                else {                    alert_float('error', response.message);                }                $('#dtModal').modal('hide');            })            .fail(function (err) {                htmlError = '';                for (var [ el, message ] of Object.entries(err.responseJSON.errors)) {                    htmlError += `<div>${message}</div>`;                }                $(".show_error").html(htmlError);                alert_float('error',htmlError);            });            return false;        }    });    </script></div>